import React from 'react';
import { Card, Stack, Divider, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'Unknown City',
    temperature = 0,
    condition = 'Clear',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <div role="region" aria-label="Weather forecast">
      <Card shadow="md" padding={24} radius="lg" border={true}>
        <Stack gap={16}>
          {/* Header */}
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text 
              variant="body" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>

          {/* Current Weather */}
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              {temperature}°{unit}
            </Heading>
            <Stack gap={2} align="end">
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity: {humidity}%
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind: {windSpeed} km/h
              </Text>
            </Stack>
          </Stack>

          <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          {/* Forecast Strip */}
          <Stack direction="horizontal" justify="between" wrap={true} gap={16}>
            {forecast.map((item, index) => (
              <Stack key={index} align="center" gap={8}>
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day ?? 'N/A'}
                </Text>
                <Text size="xl">{item.icon ?? '☁️'}</Text>
                <Stack direction="horizontal" gap={4}>
                  <Text variant="bodySmall" weight="semibold">
                    {item.high ?? 0}°
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.low ?? 0}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>
    </div>
  );
}
